arguments.command:
# The $d.147 symbols look like ARM mapping symbols. Let me try to find the actual
# function by looking at the dynamic symbol table near those addresses
readelf -W --dyn-syms /tmp/mono_nosym.so 2>/dev/null | awk '
  /FUNC/ {
    addr = strtonum("0x" $2)
    size = strtonum($3)
    name = $8
    if (addr > 0 && name != "") {
      funcs[addr] = name
      sizes[addr] = size
    }
  }
  END {
    target1 = 0x2f4b20
    target2 = 0x2f4c84
    n = asorti(funcs, sorted, "@ind_num_asc")
    for (i = 1; i <= n; i++) {
      a = sorted[i] + 0
      s = sizes[sorted[i]] + 0
      if (a <= target1 && a + s > target1) {
        printf "0x2f4b20 is in %s (base=0x%x, size=%d, offset=+0x%x)\n", funcs[sorted[i]], a, s, target1 - a
      }
      if (a <= target2 && a + s > target2) {
        printf "0x2f4c84 is in %s (base=0x%x, size=%d, offset=+0x%x)\n", funcs[sorted[i]], a, s, target2 - a
      }
    }
  }
'

