arguments.command:
# Try with nm on the debug file to find nearest symbols
nm --defined-only /tmp/mono_dbg 2>/dev/null | sort | awk '
  {
    addr = strtonum("0x" $1)
    if (addr <= 0x2f4b20) last1 = $0
    if (addr <= 0x2f4c84) last2 = $0
    if (addr > 0x2f4b20 && !printed1) { printf "0x2f4b20: prev=%s\n           next=%s\n", last1, $0; printed1=1 }
    if (addr > 0x2f4c84 && !printed2) { printf "0x2f4c84: prev=%s\n           next=%s\n", last2, $0; printed2=1 }
  }
' 2>&1

