# Those are ARM data/mapping symbols. Let me filter to only FUNC/OBJECT type symbols
nm --defined-only /tmp/mono_dbg 2>/dev/null | grep -E ' [TtWw] ' | sort | awk '
  {
    addr = strtonum("0x" $1)
    if (addr <= 0x2f4b20) { last1_addr = addr; last1 = $0 }
    if (addr <= 0x2f4c84) { last2_addr = addr; last2 = $0 }
    if (addr > 0x2f4b20 && !printed1) { printf "0x2f4b20: prev=%s (offset=+0x%x)\n           next=%s\n", last1, 0x2f4b20 - last1_addr, $0; printed1=1 }
    if (addr > 0x2f4c84 && !printed2) { printf "0x2f4c84: prev=%s (offset=+0x%x)\n           next=%s\n", last2, 0x2f4c84 - last2_addr, $0; printed2=1 }
  }
' 2>&1

